#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
typedef long long ll;
inline ll read()
{
	ll res=0;char ch=getchar();bool f=0;while(ch<'0'||ch>'9')f^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return f?-res:res; 
}
const int N=1e5+10;
const ll INF=2e18;
inline void CV(vector<int> &v){vector<int> t;t.swap(v);}
vector<int> G[N];int n,fa[N]; ll d[N],a[N],dp[N];
vector<int> Tmp;
inline bool check(int u,ll K)
{
	ll tmp=K,sum=0;
	for(int v:G[u])
	{
		ll D=d[v]-K;if(D>=0)continue;D=-D;
		if(D>min(tmp,dp[v]))return false;tmp-=D;
	}
	return true;
}
inline void dfs(int u)
{
	if(!G[u].size()){dp[u]=INF;return;}
	ll sum=0;for(int v:G[u])dfs(v),sum+=dp[v],sum>=INF?sum=INF:0;
	ll l=0,r=sum,mid;while(l<=r)check(u,mid=(l+r)>>1)?l=mid+1:r=mid-1;
//	printf("cnm :: %d %d\n",u,check(u,3));
	dp[u]=l-1;return;
}
inline void Solve()
{
	n=read();
	rep(1,n,i)CV(G[i]);
	rep(2,n,i)
	{
		fa[i]=read();
		G[fa[i]].push_back(i);
	}
	rep(1,n,i)
	{
		a[i]=read();
		d[i]=a[i]-a[fa[i]];
	}
	rep(2,n,i)if(d[i]>0){puts("Shuiniao");return;}
	if(d[1]<=0){puts("Huoyu");return;}
	rep(2,n,i)d[i]=-d[i];dfs(1);
//	rep(1,n,i)printf("%lld ",d[i]);puts("");
//	rep(1,n,i)printf("%lld ",dp[i]);puts("");
	puts(dp[1]>=d[1]?"Huoyu":"Shuiniao");
}
int main()
{
//	freopen("water4.in","r",stdin);
//	freopen("water4/.out","w",stdout);
	read();
	int T=read();
	while(T--)Solve();
//	system("fc water2.out water2.ans");
	return 0;
}
